import { Component, Inject } from '@angular/core';
import { MatFormField } from '@angular/material/form-field';
import { MatOption } from '@angular/material/core';
import { MatInput } from '@angular/material/input';
import { MatLabel } from '@angular/material/form-field';
import { MatSelect } from '@angular/material/select';
import { MatIcon } from '@angular/material/icon';
import { MatButton } from '@angular/material/button';
import { MatTableModule, MatTableDataSource } from '@angular/material/table';
import { FormGroup, Validators, FormBuilder, FormArray } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { MatError } from '@angular/material/form-field';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';
import { CdkTextareaAutosize } from '@angular/cdk/text-field';

@Component({
  selector: 'app-multiple-vessel-creation',
  standalone: true,
  imports: [MatFormField, MatInput, MatSelect, MatOption, MatIcon, MatButton, MatTableModule, MatError, CommonModule, ReactiveFormsModule, CdkTextareaAutosize],
  templateUrl: './multiple-vessel-creation.component.html',
  styleUrl: './multiple-vessel-creation.component.css'
})
export class MultipleVesselCreationComponent {
  vesselCreationForm: FormGroup;
  isEditMode = false;
  displayedColumns: string[] = ['sno', 'field_name', 'data_type', 'is_mandatory', 'action'];
  dataSource = new MatTableDataSource<any>([]);
  displayDropDownDataColumn: boolean = false;

  constructor(
    private fb: FormBuilder,
    private dialogRef: MatDialogRef<MultipleVesselCreationComponent>,
    @Inject(MAT_DIALOG_DATA) public existingdata: any
  ) {
    this.isEditMode = !!existingdata?.isEditMode;
    const initialData = existingdata?.vessels || [existingdata].filter(Boolean);
    this.vesselCreationForm = this.fb.group({
      vessels: this.fb.array(
        initialData.length > 0
          ? initialData.map((vessel: any) => this.createVesselGroup(vessel))
          : [this.createVesselGroup()]
      )
    });
    this.updateDataSource();
  }

  get vesselsArray() {
    return this.vesselCreationForm.get('vessels') as FormArray;
  }

  createVesselGroup(vessel?: any): FormGroup {
    return this.fb.group({
      field_name: [vessel?.field_name || '', Validators.required],
      data_type: [vessel?.data_type || '', Validators.required],
      is_mandatory: [vessel?.is_mandatory, Validators.required],
      showDropDownField: [vessel?.data_type === 'select' || false],
      dropdown_input: [vessel?.dropdown_input || '', vessel?.data_type === 'select' ? Validators.required : []]
    });
  }

  updateDataSource(): void {
    this.dataSource.data = this.vesselsArray.controls.map((control, index) => ({ index, control }));
  }

  addVesselRow(): void {
    this.vesselsArray.push(this.createVesselGroup());
    this.updateDataSource();
  }

  removeVesselRow(index: number): void {
    if (this.vesselsArray.length > 1) {
      this.vesselsArray.removeAt(index);
      this.updateDataSource();
    }
  }

  saveVessels(): void {
    if (this.vesselCreationForm.valid) {
      this.dialogRef.close(this.vesselsArray.value);
    } else {
      this.vesselCreationForm.markAllAsTouched();
    }
  }

  onClose(): void {
    this.dialogRef.close();
  }


  onDataTypeSelect(event: any, element: any): void {
    const control = element.control;
    if (event.value === 'select') {
      control.get('showDropDownField')?.setValue(true);
    }
    else {
      control.get('showDropDownField')?.setValue(false);
    }
  }

}


